mapper.select:
SELECT  FROM circle c WHERE c.region=#{region} AND c.status=1 AND c.is_deleted=FALSE
AND #{userId} IS NOT NULL AND EXISTS(SELECT 1 FROM circle_member cm WHERE cm.circle_id=c.id AND cm.user_id=#{userId})
ORDER BY c.sort DESC,c.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT u.id,u.nickname,u.avatar,u.signature,u.level,cm.created_at joined_at FROM circle_member cm
JOIN app_user u ON u.id=cm.user_id WHERE cm.circle_id=#{circleId} AND u.status=1 AND u.is_deleted=FALSE
ORDER BY cm.id DESC LIMIT #{limit} OFFSET #{offset}
